section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/accessibility-as-code.json",
  "title": "Accessibility as Code",
  "type": "object",
  "required": [
    "artefact_id",
    "framework",
    "unit_test_patterns",
    "integration_test_routes",
    "ci_job_id",
    "known_issues_policy",
    "owner",
    "last_touched",
    "template_version",
    "status"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "framework": {
      "type": "string",
      "description": "react|vue|svelte|...; testing stack"
    },
    "unit_test_patterns": {
      "type": "array",
      "minItems": 1,
      "description": "list of test patterns asserting role + name"
    },
    "integration_test_routes": {
      "type": "array",
      "minItems": 1,
      "description": "routes axe runs against"
    },
    "ci_job_id": {
      "type": "string",
      "minLength": 1
    },
    "known_issues_policy": {
      "type": "string",
      "minLength": 1,
      "description": "policy for suppression + expiry"
    }
  },
  "additionalProperties": false
}
